const checkpoints = [];

// Load instrumentation search params
let searchParams = null;
try { searchParams = JSON.parse(localStorage.getItem('task1_programSearchParams') || 'null'); } catch (e) { searchParams = null; }

// Load core data
let programs = [];
let campuses = [];
let applications = [];
try { programs = JSON.parse(localStorage.getItem('programs') || '[]') || []; } catch (e) {}
try { campuses = JSON.parse(localStorage.getItem('campuses') || '[]') || []; } catch (e) {}
try { applications = JSON.parse(localStorage.getItem('enrollment_applications') || '[]') || []; } catch (e) {}

// Helper: distance in miles using haversine
function distanceMiles(lat1, lon1, lat2, lon2) {
  if ([lat1, lon1, lat2, lon2].some(v => typeof v !== 'number' || isNaN(v))) return null;
  const toRad = deg => (deg * Math.PI) / 180;
  const R = 3958.8;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
            Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

// Resolve search origin coordinates from postal code 94105
const originPostal = '94105';
const originCampuses = campuses.filter(c => c && c.postal_code === originPostal && typeof c.latitude === 'number' && typeof c.longitude === 'number');
let originLat = null, originLon = null;
if (originCampuses.length) {
  originLat = originCampuses.reduce((sum, c) => sum + c.latitude, 0) / originCampuses.length;
  originLon = originCampuses.reduce((sum, c) => sum + c.longitude, 0) / originCampuses.length;
}

// Compute qualifying programs based on task criteria
const maxMonthly = 1500;
const maxMiles = 5;
let qualifyingPrograms = programs.filter(p => {
  if (!p) return false;
  if (p.age_group_code !== 'toddlers_2_3') return false;
  if (p.schedule_type !== 'full_time_5_days') return false;
  if (typeof p.monthly_tuition !== 'number' || p.monthly_tuition > maxMonthly) return false;
  const campus = campuses.find(c => c.id === p.campus_id);
  if (!campus) return false;
  if (originLat == null || originLon == null || typeof campus.latitude !== 'number' || typeof campus.longitude !== 'number') return false;
  const d = distanceMiles(originLat, originLon, campus.latitude, campus.longitude);
  return d != null && d <= maxMiles;
});

// Identify the cheapest qualifying program
let cheapestProgram = null;
if (qualifyingPrograms.length) {
  cheapestProgram = qualifyingPrograms.slice().sort((a, b) => (a.monthly_tuition || 0) - (b.monthly_tuition || 0))[0];
}

// ---- Checkpoint 1 (0.30): User searched with correct filters for this task ----
const cp1Passed = !!searchParams &&
  searchParams.ageGroupCode === 'toddlers_2_3' &&
  searchParams.postalCode === originPostal &&
  (typeof searchParams.distanceMiles === 'number' && searchParams.distanceMiles >= maxMiles) &&
  Array.isArray(searchParams.scheduleTypes) && searchParams.scheduleTypes.includes('full_time_5_days') &&
  typeof searchParams.maxMonthlyTuition === 'number' && searchParams.maxMonthlyTuition <= maxMonthly &&
  (!searchParams.sortBy || searchParams.sortBy === 'price_low_high');
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// Find applications to qualifying programs
const qualifyingProgramIds = new Set(qualifyingPrograms.map(p => p.id));
const qualifyingApps = applications.filter(app => app && qualifyingProgramIds.has(app.program_id));

// ---- Checkpoint 2 (0.30): User started enrollment for some qualifying program ----
const cp2Passed = qualifyingApps.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// ---- Checkpoint 3 (0.40): User started enrollment specifically for the cheapest qualifying program ----
let cp3Passed = false;
if (cheapestProgram) {
  cp3Passed = applications.some(app => app && app.program_id === cheapestProgram.id);
}
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let tourRequests = [];
let campuses = [];
try { tourRequests = JSON.parse(localStorage.getItem('tour_requests') || '[]') || []; } catch (e) {}
try { campuses = JSON.parse(localStorage.getItem('campuses') || '[]') || []; } catch (e) {}

// Find the campus in ZIP 94105 dynamically
const downtownCampus = campuses.find(c => c && c.postal_code === '94105');
const downtownId = downtownCampus ? downtownCampus.id : null;

function isInDateRangeJune10to20(date) {
  if (!(date instanceof Date) || isNaN(date.getTime())) return false;
  const y = date.getUTCFullYear();
  const m = date.getUTCMonth(); // 0=Jan
  const d = date.getUTCDate();
  if (y !== 2026 || m !== 5) return false; // June 2026
  return d >= 10 && d <= 20;
}

function isWeekdayMorning(date) {
  if (!(date instanceof Date) || isNaN(date.getTime())) return false;
  const day = date.getUTCDay(); // 0=Sun,1=Mon...
  const isWeekday = day >= 1 && day <= 5;
  const hour = date.getUTCHours();
  const minute = date.getUTCMinutes();
  const isMorning = hour >= 10 && (hour < 11 || (hour === 11 && minute <= 30));
  return isWeekday && isMorning;
}

// Filter requests that match campus, visit type, and date/time window
const matchingCore = tourRequests.filter(req => {
  if (!req || !downtownId) return false;
  if (req.campus_id !== downtownId) return false;
  if (req.visit_type !== 'in_person_tour') return false;
  const start = new Date(req.visit_start);
  if (!isInDateRangeJune10to20(start)) return false;
  if (!isWeekdayMorning(start)) return false;
  return true;
});

// ---- CP1 (0.40): At least one in-person tour at 94105 campus in correct weekday morning window between June 10–20 ----
const cp1Passed = matchingCore.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// Further filter for correct child details
const matchingWithChild = matchingCore.filter(req => {
  return typeof req.number_of_children === 'number' && req.number_of_children === 1 &&
         typeof req.child_age_years === 'number' && Math.round(req.child_age_years) === 3;
});

// ---- CP2 (0.30): Request also has one child age ~3 ----
const cp2Passed = matchingWithChild.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// Further filter for correct parent details
const matchingWithParent = matchingWithChild.filter(req => {
  return req.parent_name === 'Alex Rivera' && req.parent_email === 'alex.rivera@example.com';
});

// ---- CP3 (0.30): Request also includes the given parent name and email ----
const cp3Passed = matchingWithParent.length > 0;
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let comparisons = [];
let waitlistEntries = [];
let programs = [];
let campuses = [];
try { comparisons = JSON.parse(localStorage.getItem('program_comparisons') || '[]') || []; } catch (e) {}
try { waitlistEntries = JSON.parse(localStorage.getItem('waitlist_entries') || '[]') || []; } catch (e) {}
try { programs = JSON.parse(localStorage.getItem('programs') || '[]') || []; } catch (e) {}
try { campuses = JSON.parse(localStorage.getItem('campuses') || '[]') || []; } catch (e) {}

// Identify Lakeside campus dynamically by description hint "Lake Merced" or by id
const lakesideCampus = campuses.find(c => c && (c.description || '').toLowerCase().includes('lake merced')) || campuses.find(c => c && c.id === 'lakeside_campus');
const lakesideId = lakesideCampus ? lakesideCampus.id : null;

// Find comparisons that include both half-day and full-day preschool programs at Lakeside
const qualifyingComparisons = [];

comparisons.forEach(cmp => {
  if (!cmp || !Array.isArray(cmp.program_ids) || !cmp.program_ids.length) return;
  const cmpPrograms = cmp.program_ids
    .map(id => programs.find(p => p && p.id === id))
    .filter(p => !!p);
  if (!cmpPrograms.length) return;

  const allAtLakeside = cmpPrograms.every(p => p.campus_id === lakesideId);
  const allPreschool = cmpPrograms.every(p => p.age_group_code === 'preschool_3_5');
  const hasHalf = cmpPrograms.some(p => p.schedule_type === 'half_day');
  const hasFull = cmpPrograms.some(p => p.schedule_type === 'full_day');

  if (!allAtLakeside || !allPreschool || !hasHalf || !hasFull) return;

  // Compute cheaper program by annual tuition
  let cheapest = null;
  cmpPrograms.forEach(p => {
    const annual = typeof p.annual_tuition === 'number' ? p.annual_tuition : (p.monthly_tuition || 0) * 12;
    if (!cheapest || annual < cheapest.annual) {
      cheapest = { program: p, annual };
    }
  });
  if (cheapest) {
    qualifyingComparisons.push({ comparison: cmp, cheapestProgramId: cheapest.program.id });
  }
});

// ---- CP1 (0.40): At least one comparison between half-day and full-day preschool programs at Lakeside ----
const cp1Passed = qualifyingComparisons.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// Among those comparisons, check for waitlist entries on the cheaper program with correct age and month
let hasCheaperWaitlist = false;
let hasCheaperWaitlistWithName = false;

qualifyingComparisons.forEach(q => {
  const entriesForCheapest = waitlistEntries.filter(w => w && w.program_id === q.cheapestProgramId);
  if (!entriesForCheapest.length) return;

  entriesForCheapest.forEach(w => {
    const ageOk = typeof w.child_age_years === 'number' && Math.round(w.child_age_years) === 4;
    const monthOk = (w.desired_start_month || '').toLowerCase() === 'september';
    if (ageOk && monthOk) {
      hasCheaperWaitlist = true;
      if (w.child_name === 'Jordan Lee') {
        hasCheaperWaitlistWithName = true;
      }
    }
  });
});

// ---- CP2 (0.30): User joined the waitlist for the cheaper program with a 4-year-old and September start month ----
checkpoints.push({ passed: hasCheaperWaitlist, weight: 0.30 });

// ---- CP3 (0.30): The matching waitlist entry also uses the child name "Jordan Lee" ----
checkpoints.push({ passed: hasCheaperWaitlistWithName, weight: 0.30 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

