try { calcState = JSON.parse(localStorage.getItem('tuition_calculator_state') || 'null'); } catch (e) { calcState = null; }
try { quotes = JSON.parse(localStorage.getItem('tuition_quotes') || '[]') || []; } catch (e) {}

