  cp1Passed = ageMatch && daysMatch && timesMatch && budgetMatch;
}
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// ---- CP2 (0.60): A saved tuition quote uses that configuration and the specified email and quote name ----
let cp2Passed = false;
if (calcState && calcState.lastEstimate && quotes.length) {
  const est = calcState.lastEstimate;
  quotes.forEach(q => {
    if (cp2Passed) return;
    if (!q) return;
    const emailOk = q.email === 'parent@example.com';
    const nameOk = q.quote_name === 'Infant M/W/F extended';
    const ageOk = q.age_group_code === est.age_group_code && est.age_group_code === 'infants_0_18';
    const daysOk = Array.isArray(q.days_of_week) && q.days_of_week.length === est.days_of_week.length &&
      q.days_of_week.slice().sort().every((d, i) => d === est.days_of_week.slice().sort()[i]);
    const timesOk = q.dropoff_time === est.dropoff_time && q.pickup_time === est.pickup_time;
    const budgetOk = typeof q.max_monthly_budget === 'number' ? q.max_monthly_budget === calcState.maxMonthlyBudget : true;
    if (emailOk && nameOk && ageOk && daysOk && timesOk && budgetOk) {
      cp2Passed = true;
    }
  });
}
