const checkpoints = [];

let events = [];
let rsvps = [];
try { events = JSON.parse(localStorage.getItem('events') || '[]') || []; } catch (e) {}
try { rsvps = JSON.parse(localStorage.getItem('event_rsvps') || '[]') || []; } catch (e) {}

// Determine next month from current date
const now = new Date();
let year = now.getUTCFullYear();
let monthIndex = now.getUTCMonth() + 1; // next month (0-11)
if (monthIndex > 11) { monthIndex = 0; year += 1; }

const rangeStart = new Date(Date.UTC(year, monthIndex, 1, 0, 0, 0, 0));
const rangeEnd = new Date(Date.UTC(year, monthIndex + 1, 0, 23, 59, 59, 999));

// Filter qualifying events: next month, family_event, free, Sat/Sun afternoons
const qualifyingEvents = events.filter(ev => {
  if (!ev || !ev.start_datetime) return false;
  const dt = new Date(ev.start_datetime);
  if (isNaN(dt.getTime())) return false;
  if (dt < rangeStart || dt > rangeEnd) return false;
  if (ev.event_type !== 'family_event') return false;
  if (!ev.is_free) return false;
  const day = (ev.day_of_week || '').toLowerCase();
  if (day !== 'saturday' && day !== 'sunday') return false;
  const tod = (ev.time_of_day || '').toLowerCase();
  if (tod !== 'afternoon') return false;
  return true;
}).sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));

const targetEvents = qualifyingEvents.slice(0, 2);

function attendeesForEvent(eventId) {
  return rsvps
    .filter(r => r && r.event_id === eventId && r.status !== 'canceled')
    .reduce((sum, r) => sum + (typeof r.number_of_attendees === 'number' ? r.number_of_attendees : 0), 0);
}

// ---- CP1 (0.50): At least 3 attendees RSVP'd for the earliest qualifying event ----
let cp1Passed = false;
if (targetEvents[0]) {
  const total = attendeesForEvent(targetEvents[0].id);
  cp1Passed = total >= 3;
}
checkpoints.push({ passed: cp1Passed, weight: 0.50 });

// ---- CP2 (0.50): At least 3 attendees RSVP'd for the second earliest qualifying event ----
let cp2Passed = false;
if (targetEvents[1]) {
  const total = attendeesForEvent(targetEvents[1].id);
  cp2Passed = total >= 3;
}
checkpoints.push({ passed: cp2Passed, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

